        [ 2,  0,  2,  0,  6,  0,  2,  0,  6,  0,  2,  0, 10,  0,  6,  0,  2,  0, 10,  0,  6,  0,  2,  0, 14,  0, 10,  0,  2,  0,  6,  0,  0,  0,  0,  2,  0, 14,  0, 10,  0,  2,  2, ],  # 116 Lv
